<?php namespace App\Repositories\Transport;use App\Repositories\BaseRepository;use App\Models\Transport\TransportTracking;use Illuminate\Database\Eloquent\Collection;class TransportTrackingRepository extends BaseRepository{    public function __construct(TransportTracking $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByVehicle(int $vehicleId): Collection    {        return $this->findByField('vehicle_id', $vehicleId);    }    public function findByRoute(int $routeId): Collection    {        return $this->findByField('route_id', $routeId);    }    public function getByDate(string $date): Collection    {        return $this->query()->whereDate('tracking_date', $date)->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('tracking_date', [$startDate, $endDate])->get();    }    public function getLatestLocation(int $vehicleId): ?TransportTracking    {        return $this->query()->where('vehicle_id', $vehicleId)->orderBy('tracked_at', 'desc')->first();    }    public function getVehicleHistory(int $vehicleId, string $date): Collection    {        return $this->query()->where('vehicle_id', $vehicleId)->whereDate('tracking_date', $date)->orderBy('tracked_at', 'asc')->get();    }    public function recordLocation(array $data): TransportTracking    {        return $this->create($data);    }    public function getVehiclesOnRoute(int $routeId): Collection    {        return $this->query()->where('route_id', $routeId)->whereDate('tracking_date', now())->distinct('vehicle_id')->get();    }    public function getTodayTrackings(): Collection    {        return $this->query()->whereDate('tracking_date', now())->orderBy('tracked_at', 'desc')->get();    }}